// Setting innerHTML via React
<div dangerouslySetInnerHTML={{ __html: "<p>Hello <b>world</b></p>" }} />

// Equivalent DOM operation React performs internally:
element.innerHTML = "<p>Hello <b>world</b></p>";

function ArticleBody({ htmlContent }) {
  return (
    <article
      className="prose"
      dangerouslySetInnerHTML={{ __html: htmlContent }}
    />
  );
}

// A user comment containing a script payload:
const userInput = '<img src="x" onerror="fetch(\'/steal?c=\'+document.cookie)">';

// Rendering it directly is a security hole
<div dangerouslySetInnerHTML={{ __html: userInput }} />
// Browser executes the onerror handler and leaks the cookie

// href="javascript:..." is also an attack vector
const malicious = '<a href="javascript:alert(1)">Click me</a>';

import DOMPurify from 'dompurify';

function SafeHtml({ html }) {
  const sanitised = DOMPurify.sanitize(html);
  return <div dangerouslySetInnerHTML={{ __html: sanitised }} />;
}

// Stricter configuration — allowlist of tags and attributes
const STRICT_CONFIG = {
  ALLOWED_TAGS: ['b', 'i', 'em', 'strong', 'a', 'p', 'br', 'ul', 'ol', 'li'],
  ALLOWED_ATTR: ['href', 'title', 'target'],
};

function Comment({ html }) {
  const clean = DOMPurify.sanitize(html, STRICT_CONFIG);
  return <p dangerouslySetInnerHTML={{ __html: clean }} />;
}

import { useMemo } from 'react';
import DOMPurify from 'dompurify';

function Article({ markdown, theme }) {
  // Only re-sanitise when markdown changes, not on unrelated re-renders
  const __html = useMemo(
    () => DOMPurify.sanitize(convertMarkdownToHtml(markdown)),
    [markdown]
  );

  return (
    <article
      className={`prose prose-${theme}`}
      dangerouslySetInnerHTML={{ __html }}
    />
  );
}

// Server (Next.js / Remix)
export async function getServerSideProps() {
  const raw = await fetchArticleHtml();
  const html = sanitizeOnServer(raw);  // sanitize-html or DOMPurify+jsdom
  return { props: { html } };
}

// Client renders pre-sanitised HTML — no double-sanitisation mismatch
function Article({ html }) {
  return <div dangerouslySetInnerHTML={{ __html: html }} />;
}

// onClick on this anchor DOES NOT fire — it is inside injected HTML
<div dangerouslySetInnerHTML={{ __html: '<a onClick="...">link</a>' }} />

// Intercept clicks with native event delegation on the container
const ref = useRef(null);
useEffect(() => {
  const el = ref.current;
  const handler = (e) => {
    if (e.target.tagName === 'A') handleLinkClick(e.target.href);
  };
  el.addEventListener('click', handler);
  return () => el.removeEventListener('click', handler);
}, []);

<div ref={ref} dangerouslySetInnerHTML={{ __html: sanitisedContent }} />

// User comments: very restrictive
const COMMENT_CONFIG = {
  ALLOWED_TAGS: ['b', 'i', 'em', 'strong', 'a', 'br'],
  ALLOWED_ATTR: ['href'],
  ALLOW_DATA_ATTR: false,
};

// Blog articles: more permissive
const ARTICLE_CONFIG = {
  ALLOWED_TAGS: [
    'h1', 'h2', 'h3', 'p', 'ul', 'ol', 'li', 'blockquote',
    'pre', 'code', 'a', 'img', 'table', 'tr', 'td', 'th',
  ],
  ALLOWED_ATTR: ['href', 'src', 'alt', 'title', 'class', 'id'],
  ALLOW_DATA_ATTR: true,
};

const clean = DOMPurify.sanitize(rawHtml, COMMENT_CONFIG);

// DOMPurify hook to add rel="noopener noreferrer" to all _blank links
DOMPurify.addHook('afterSanitizeAttributes', (node) => {
  if (node.tagName === 'A' && node.getAttribute('target') === '_blank') {
    node.setAttribute('rel', 'noopener noreferrer');
  }
});

// Or post-process in useEffect
useEffect(() => {
  const links = containerRef.current?.querySelectorAll('a[target="_blank"]');
  links?.forEach((a) => a.setAttribute('rel', 'noopener noreferrer'));
}, [htmlContent]);

# Server header (Next.js, Express, etc.)
Content-Security-Policy:
  default-src 'self';
  script-src 'self';
  style-src 'self' 'unsafe-inline';
  img-src 'self' data: https:;
  object-src 'none';

// Mark sanitised strings so unsanitised strings cannot accidentally be passed
type SanitisedHtml = string & { __brand: 'sanitised' };

function sanitise(raw: string): SanitisedHtml {
  return DOMPurify.sanitize(raw) as SanitisedHtml;
}

// Wrapper component only accepts a branded type
function SafeHtmlRenderer({ html }: { html: SanitisedHtml }) {
  return <div dangerouslySetInnerHTML={{ __html: html }} />;
}

// TypeScript error — unsanitised string rejected at compile time
<SafeHtmlRenderer html={rawUserInput} />  // ← Error
<SafeHtmlRenderer html={sanitise(rawUserInput)} />  // ← OK

import { render, screen } from '@testing-library/react';
import DOMPurify from 'dompurify';

function SafeHtml({ html }) {
  return (
    <div
      data-testid="content"
      dangerouslySetInnerHTML={{ __html: DOMPurify.sanitize(html) }}
    />
  );
}

test('renders safe HTML content', () => {
  render(<SafeHtml html="<p>Hello <b>world</b></p>" />);
  const container = screen.getByTestId('content');
  expect(container.querySelector('b')).toHaveTextContent('world');
});

test('strips dangerous script tags', () => {
  render(<SafeHtml html='<script>window.__hacked = true</script><p>Safe text</p>' />);
  const container = screen.getByTestId('content');
  expect(container.querySelector('script')).toBeNull();
  expect(window.__hacked).toBeUndefined();
});

test('strips event handler attributes', () => {
  render(<SafeHtml html='<img src="x" onerror="alert(1)">' />);
  const img = screen.getByTestId('content').querySelector('img');
  expect(img?.getAttribute('onerror')).toBeNull();
});

// Problem: typing in an input inside injected HTML loses focus on re-render
function LivePreview({ html }) {
  return <div dangerouslySetInnerHTML={{ __html: html }} />;
}
// Any state typed into an input inside html is reset every time html changes

// Fix: debounce the html update to reduce re-renders while the user types
function LivePreview({ rawHtml }) {
  const [html, setHtml] = useState(rawHtml);

  useEffect(() => {
    const id = setTimeout(() => setHtml(rawHtml), 400);
    return () => clearTimeout(id);
  }, [rawHtml]);

  return <div dangerouslySetInnerHTML={{ __html: DOMPurify.sanitize(html) }} />;
}

import { useEffect, useRef } from 'react';
import Prism from 'prismjs';
import DOMPurify from 'dompurify';

function CodeBlock({ code, language }) {
  const highlighted = Prism.highlight(
    code,
    Prism.languages[language] ?? Prism.languages.plain,
    language
  );

  // Prism's output is safe — it only adds <span> with class attrs
  // DOMPurify as extra defence-in-depth
  const safeHtml = DOMPurify.sanitize(highlighted, {
    ALLOWED_TAGS: ['span'],
    ALLOWED_ATTR: ['class'],
  });

  return (
    <pre>
      <code
        className={`language-${language}`}
        dangerouslySetInnerHTML={{ __html: safeHtml }}
      />
    </pre>
  );
}

// This does NOT render React components inside the HTML string
const htmlWithTooltip = '<span data-tip="info">Hover me</span>';
<div dangerouslySetInnerHTML={{ __html: htmlWithTooltip }} />
// The data-tip attribute is there in the DOM, but no React component watches it

// Solution: use a structured renderer that maps nodes to React
// e.g., react-markdown with custom components
import ReactMarkdown from 'react-markdown';

<ReactMarkdown
  components={{
    code: ({ children }) => <CodeHighlight>{children}</CodeHighlight>,
    a: ({ href, children }) => <TrackedLink href={href}>{children}</TrackedLink>,
  }}
>
  {markdownString}
</ReactMarkdown>
